from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/webhook', methods=['POST'])
def webhook():
    # Extract data from the request
    data = request.get_json()

    # Validate the request internally
    if not validate_request(data):
        return jsonify({"error": "Invalid request"}), 400

    # Process the webhook event
    process_event(data)

    return jsonify({"status": "success"}), 200

def validate_request(data):
    # Add your validation logic here
    # For example, check if required fields are present and valid
    if 'event_type' not in data or 'transaction_id' not in data:
        return False
    return True

def process_event(data):
    # Add your event processing logic here
    print(f"Processing event of type: {data['event_type']} with transaction ID: {data['transaction_id']}")

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8080)